  always @(negedge clk) begin
    if ((o_valid_tb == '1) && (i_ready_tb == '1)) begin
      i <= i + 1;
    end
  end  

   initial begin
    @(posedge reset_done);
    @(posedge clk); 
    forever begin 
      o_ready_tb <= $urandom % 2; 
      @(posedge clk); 
